// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		// set the message on load and change
		showRequestCommentsMessage();
		return;
	}
	showRequestCommentsMessage();

	function showRequestCommentsMessage(){
		var isNewRecord = g_form.isNewRecord();
		if(isNewRecord){
			// set the message on load and change
			g_form.showFieldMsg('u_request_comments', getMessage('Tasker - Please add your request comments before submitting your request'),'info');
		}
	}

}
